   254→      INSERT INTO candidate_profiles (user_id, resume_url)
   255→      VALUES ($1, $2)
   256→      ON CONFLICT (user_id) DO UPDATE SET resume_url = $2, updated_at = NOW()
   257→    `, [req.user.id, uploadResult.file.url]);
   258→
   259→    // Extract text from the resume (supports PDF, DOCX, and plain text)
   260→    let parsedData = null;
   261→    try {
   262→      // Extract text from the file buffer
   263→      const resumeText = await extractTextFromFile(req.file.buffer, req.file.mimetype);
   264→
   265→      if (resumeText && resumeText.trim().length > 50) {
   266→        // Get user's subscription for tracking
   267→        const user = await pool.query('SELECT stripe_subscription_id FROM users WHERE id = $1', [req.user.id]);
   268→        const subscriptionId = user.rows[0]?.stripe_subscription_id;
   269→
   270→        // Parse with AI, with a 30-second timeout
   271→        const parsePromise = parseResume(resumeText.substring(0, 15000), { subscriptionId });
   272→        const timeoutPromise = new Promise((_, reject) =>
   273→          setTimeout(() => reject(new Error('AI parsing timeout')), 30000)
   274→        );
   275→
   276→        parsedData = await Promise.race([parsePromise, timeoutPromise]);
   277→
   278→        // Update the record with parsed data
   279→        await pool.query(`
   280→          UPDATE parsed_resumes
   281→          SET parsed_data = $1, parsing_status = 'completed', parsed_at = NOW()
   282→          WHERE id = $2
   283→        `, [JSON.stringify(parsedData), resumeRecord.rows[0].id]);
   284→
   285→        console.log(`Successfully parsed ${req.file.mimetype} resume for user ${req.user.id}`);
   286→
   287→        // ====== AUTO-APPLY parsed data to profile ======
   288→        try {
   289→          const applySummary = { profile: false, experience: 0, education: 0, skills: 0 };
   290→
   291→          // 1. Apply contact/profile info
   292→          if (parsedData.contact) {
   293→            await pool.query(`
   294→              INSERT INTO candidate_profiles (user_id, headline, bio, location, phone, linkedin_url, github_url, portfolio_url, years_experience)
   295→              VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
   296→              ON CONFLICT (user_id) DO UPDATE SET
   297→                headline = COALESCE(NULLIF($2, ''), candidate_profiles.headline),
   298→                bio = COALESCE(NULLIF($3, ''), candidate_profiles.bio),
   299→                location = COALESCE(NULLIF($4, ''), candidate_profiles.location),
   300→                phone = COALESCE(NULLIF($5, ''), candidate_profiles.phone),
   301→                linkedin_url = COALESCE(NULLIF($6, ''), candidate_profiles.linkedin_url),
   302→                github_url = COALESCE(NULLIF($7, ''), candidate_profiles.github_url),
   303→                portfolio_url = COALESCE(NULLIF($8, ''), candidate_profiles.portfolio_url),
   304→                years_experience = COALESCE($9, candidate_profiles.years_experience),
   305→                updated_at = NOW()
   306→            `, [
   307→              req.user.id,
   308→              parsedData.headline || null,
   309→              parsedData.bio || null,
   310→              parsedData.contact.location || null,
   311→              parsedData.contact.phone || null,
   312→              parsedData.contact.linkedin || null,
   313→              parsedData.contact.github || null,
   314→              parsedData.contact.portfolio || null,
   315→              parsedData.years_experience || null
   316→            ]);
   317→            applySummary.profile = true;
   318→
   319→            // Update user name/email if empty
   320→            if (parsedData.contact.name) {
   321→              await pool.query(
   322→                `UPDATE users SET name = $1 WHERE id = $2 AND (name IS NULL OR name = '')`,
   323→                [parsedData.contact.name, req.user.id]
   324→              );
   325→            }
   326→          }
   327→
   328→          // 2. Apply work experience (with dedup: skip if same company+title exists)
   329→          if (parsedData.experience && Array.isArray(parsedData.experience)) {
   330→            for (let i = 0; i < parsedData.experience.length; i++) {
   331→              const exp = parsedData.experience[i];
