   383→                edu.end_date && edu.end_date !== 'Present' ? new Date(edu.end_date + '-01-01') : null,
   384→                edu.gpa || null,
   385→                JSON.stringify(edu.achievements || []),
   386→                i
   387→              ]);
   388→              applySummary.education++;
   389→            }
   390→          }
   391→
   392→          // 4. Apply skills (upsert — won't duplicate due to UNIQUE constraint)
   393→          if (parsedData.skills && Array.isArray(parsedData.skills)) {
   394→            for (const skill of parsedData.skills) {
   395→              if (!skill.name) continue;
   396→              try {
   397→                // Coerce string level names to integers
