   407→                  ON CONFLICT (user_id, skill_name) DO UPDATE SET
   408→                    category = COALESCE(NULLIF($3, ''), candidate_skills.category),
   409→                    level = GREATEST(candidate_skills.level, $4)
   410→                `, [req.user.id, skill.name, skill.category || 'technical', skillLevel]);
   411→                applySummary.skills++;
