  1642→
  1643→// Auto-fill endpoint — returns stored data for pre-populating application forms
  1644→router.get('/auto-fill/:jobId', authMiddleware, async (req, res) => {
  1645→  try {
  1646→    const jobId = req.params.jobId;
  1647→
  1648→    // Get profile data
  1649→    const profile = await pool.query(`
  1650→      SELECT cp.*, u.name, u.email FROM candidate_profiles cp
  1651→      RIGHT JOIN users u ON u.id = cp.user_id WHERE u.id = $1
  1652→    `, [req.user.id]);
  1653→
  1654→    // Get resume URL
  1655→    const resumeData = await pool.query('SELECT resume_url FROM candidate_profiles WHERE user_id = $1', [req.user.id]);
  1656→
  1657→    // Get screening questions for this job
  1658→    const job = await pool.query('SELECT screening_questions FROM jobs WHERE id = $1', [jobId]);
  1659→    const screeningQuestions = job.rows[0]?.screening_questions || [];
  1660→
  1661→    // Find past answers for similar questions
  1662→    const pastApps = await pool.query(`
  1663→      SELECT screening_answers, cover_letter FROM job_applications
  1664→      WHERE candidate_id = $1 AND screening_answers IS NOT NULL
  1665→      ORDER BY applied_at DESC LIMIT 10
  1666→    `, [req.user.id]);
  1667→
  1668→    // Build auto-fill map for screening questions
  1669→    const answerMap = {};
  1670→    for (const q of screeningQuestions) {
  1671→      // Search past answers by category or similar question text
  1672→      for (const app of pastApps.rows) {
  1673→        const answers = app.screening_answers || {};
  1674→        // Direct ID match
  1675→        if (answers[q.id]) {
  1676→          answerMap[q.id] = { value: answers[q.id], source: 'previous_application' };
  1677→          break;
  1678→        }
  1679→        // Category match
  1680→        for (const [key, val] of Object.entries(answers)) {
  1681→          if (q.category && key.includes(q.category)) {
  1682→            answerMap[q.id] = { value: val, source: 'similar_question' };
  1683→            break;
  1684→          }
  1685→        }
  1686→      }
  1687→
  1688→      // Fallback: match from profile data
  1689→      if (!answerMap[q.id] && q.category) {
  1690→        const p = profile.rows[0] || {};
  1691→        if (q.category === 'salary' && p.salary_min) {
  1692→          answerMap[q.id] = { value: `$${p.salary_min.toLocaleString()} - $${(p.salary_max || p.salary_min).toLocaleString()}`, source: 'profile' };
  1693→        } else if (q.category === 'availability' && p.availability) {
  1694→          answerMap[q.id] = { value: p.availability, source: 'profile' };
  1695→        } else if (q.category === 'relocation') {
  1696→          answerMap[q.id] = { value: p.remote_preference === 'remote' ? 'No' : 'Yes', source: 'profile' };
  1697→        } else if (q.category === 'experience') {
  1698→          const yrs = p.years_experience || 0;
  1699→          const bracket = yrs < 1 ? '0-1 years' : yrs < 3 ? '1-3 years' : yrs < 5 ? '3-5 years' : yrs < 10 ? '5-10 years' : '10+ years';
  1700→          answerMap[q.id] = { value: bracket, source: 'profile' };
  1701→        }
  1702→      }
  1703→    }
  1704→
  1705→    // Find the most recent cover letter
  1706→    const lastCoverLetter = pastApps.rows.find(a => a.cover_letter)?.cover_letter || '';
  1707→
  1708→    res.json({
  1709→      success: true,
