   545→
   546→    // Validate status against pipeline stages
   547→    if (status && !PIPELINE_STAGES.includes(status)) {
   548→      return res.status(400).json({ error: `Invalid status. Must be one of: ${PIPELINE_STAGES.join(', ')}` });
   549→    }
   550→
   551→    // Verify application belongs to company
   552→    const existing = await pool.query(
   553→      'SELECT id, job_id, candidate_id, status as old_status FROM job_applications WHERE id = $1 AND company_id = $2',
   554→      [req.params.id, req.user.company_id]
   555→    );
   556→
   557→    if (existing.rows.length === 0) {
   558→      return res.status(404).json({ error: 'Application not found' });
   559→    }
   560→
   561→    const result = await pool.query(
   562→      `UPDATE job_applications SET
   563→        status = COALESCE($1, status),
   564→        recruiter_notes = COALESCE($2, recruiter_notes),
   565→        updated_at = NOW()
   566→       WHERE id = $3
   567→       RETURNING *`,
   568→      [status, recruiter_notes, req.params.id]
   569→    );
   570→
   571→    // Log to activity feed (events table) for status changes
   572→    if (status && status !== existing.rows[0].old_status) {
   573→      try {
   574→        await pool.query(
   575→          `INSERT INTO events (user_id, event_type, event_data, created_at)
   576→           VALUES ($1, 'application_status_changed', $2, NOW())`,
   577→          [req.user.id, JSON.stringify({
   578→            application_id: parseInt(req.params.id),
   579→            candidate_id: existing.rows[0].candidate_id,
   580→            job_id: existing.rows[0].job_id,
   581→            old_status: existing.rows[0].old_status,
   582→            new_status: status,
   583→            changed_by: req.user.id,
   584→          })]
   585→        );
   586→      } catch (e) { /* non-critical */ }
   587→    }
   588→
   589→    // Update job analytics
   590→    if (status) {
