   832→// Get candidate coaching/practice history (for recruiter review)
   833→router.get('/candidates/:id/coaching', authMiddleware, requireRecruiter, async (req, res) => {
   834→  try {
   835→    const candidateId = req.params.id;
   836→
   837→    // Verify candidate has applied to one of recruiter's jobs
   838→    const hasRelation = await pool.query(
   839→      `SELECT 1 FROM job_applications ja
   840→       JOIN jobs j ON ja.job_id = j.id
   841→       WHERE ja.candidate_id = $1 AND (j.company_id = $2 OR j.user_id = $3)
   842→       LIMIT 1`,
   843→      [candidateId, req.user.company_id, req.user.id]
   844→    );
   845→
   846→    if (hasRelation.rows.length === 0) {
   847→      return res.status(403).json({ error: 'Access denied — candidate has not applied to your jobs' });
   848→    }
   849→
   850→    // Get candidate name
   851→    const candidate = await pool.query('SELECT name, email FROM users WHERE id = $1', [candidateId]);
   852→
   853→    // Get all coaching sessions
   854→    const sessions = await pool.query(
   855→      `SELECT
   856→        id, question, category, score, coaching_data, response_type,
   857→        duration_seconds, created_at
   858→       FROM practice_sessions
   859→       WHERE user_id = $1
   860→       ORDER BY created_at DESC`,
   861→      [candidateId]
   862→    );
   863→
   864→    // Get aggregate stats
   865→    const stats = await pool.query(
   866→      `SELECT
   867→        COUNT(*) as total_sessions,
   868→        AVG(score) as average_score,
   869→        MIN(score) as lowest_score,
   870→        MAX(score) as highest_score,
   871→        MIN(created_at) as first_session,
   872→        MAX(created_at) as last_session
   873→       FROM practice_sessions
   874→       WHERE user_id = $1`,
   875→      [candidateId]
   876→    );
   877→
   878→    // Calculate improvement trend
   879→    const improvement = await pool.query(
   880→      `WITH ordered AS (
   881→        SELECT score, ROW_NUMBER() OVER (ORDER BY created_at) as rn,
   882→               COUNT(*) OVER () as total
   883→        FROM practice_sessions WHERE user_id = $1
   884→      )
   885→      SELECT
   886→        AVG(CASE WHEN rn <= total/2 THEN score END) as first_half_avg,
   887→        AVG(CASE WHEN rn > total/2 THEN score END) as second_half_avg
   888→      FROM ordered`,
   889→      [candidateId]
   890→    );
   891→
   892→    let improvementPercent = null;
   893→    if (improvement.rows[0].first_half_avg && improvement.rows[0].second_half_avg) {
   894→      const firstHalf = parseFloat(improvement.rows[0].first_half_avg);
   895→      const secondHalf = parseFloat(improvement.rows[0].second_half_avg);
   896→      improvementPercent = Math.round(((secondHalf - firstHalf) / firstHalf) * 100);
   897→    }
   898→
   899→    // Category breakdown
   900→    const byCategory = await pool.query(
   901→      `SELECT category, COUNT(*) as count, AVG(score) as avg_score
   902→       FROM practice_sessions WHERE user_id = $1
   903→       GROUP BY category ORDER BY avg_score DESC`,
   904→      [candidateId]
   905→    );
   906→
   907→    const parsed = sessions.rows.map(row => ({
   908→      ...row,
   909→      coaching_data: typeof row.coaching_data === 'string' ? JSON.parse(row.coaching_data) : row.coaching_data,
   910→    }));
   911→
   912→    res.json({
   913→      success: true,
   914→      candidate: candidate.rows[0] || { name: 'Unknown', email: '' },
   915→      stats: {
   916→        total_sessions: parseInt(stats.rows[0].total_sessions) || 0,
   917→        average_score: parseFloat(stats.rows[0].average_score) || null,
   918→        lowest_score: parseFloat(stats.rows[0].lowest_score) || null,
   919→        highest_score: parseFloat(stats.rows[0].highest_score) || null,
   920→        improvement_percent: improvementPercent,
   921→        first_session: stats.rows[0].first_session,
   922→        last_session: stats.rows[0].last_session,
   923→      },
   924→      by_category: byCategory.rows,
   925→      sessions: parsed,
   926→    });
   927→  } catch (err) {
   928→    console.error('Get candidate coaching history error:', err);
   929→    res.status(500).json({ error: 'Failed to fetch coaching history' });
   930→  }
   931→});
