   933→// ============= PIPELINE STAGES =============
   934→
   935→// Valid pipeline stages in order (canonical)
   936→// Based on industry research: LinkedIn, Greenhouse, Lever, Ashby, SmartRecruiters
   937→const PIPELINE_STAGES = ['applied', 'screening', 'shortlisted', 'reviewing', 'interviewed', 'offered', 'hired', 'rejected', 'withdrawn'];
   938→
   939→// GET pipeline stages (so frontend stays in sync)
   940→router.get('/pipeline-stages', authMiddleware, requireRecruiter, (req, res) => {
   941→  const active = PIPELINE_STAGES.filter(s => !['rejected', 'withdrawn'].includes(s));
   942→  const terminal = ['rejected', 'withdrawn'];
   943→  res.json({
   944→    success: true,
   945→    stages: PIPELINE_STAGES,
