     1→const express = require('express');
     2→const pool = require('../lib/db');
     3→const { authMiddleware, optionalAuth, requireRole } = require('../lib/auth');
     4→
     5→const router = express.Router();
     6→
     7→// List jobs (public)
     8→router.get('/', optionalAuth, async (req, res) => {
     9→  try {
    10→    const { status = 'active', limit = 20, offset = 0 } = req.query;
    11→    
    12→    const result = await pool.query(
    13→      `SELECT j.*, u.company_name as poster_company
    14→       FROM jobs j
    15→       LEFT JOIN users u ON j.user_id = u.id
    16→       WHERE j.status = $1
    17→       ORDER BY j.created_at DESC
    18→       LIMIT $2 OFFSET $3`,
    19→      [status, limit, offset]
    20→    );
    21→
    22→    res.json({ jobs: result.rows });
    23→  } catch (err) {
    24→    console.error('List jobs error:', err);
    25→    res.status(500).json({ error: 'Failed to fetch jobs' });
    26→  }
    27→});
    28→
    29→// Get single job
    30→router.get('/:id', optionalAuth, async (req, res) => {
    31→  try {
    32→    const result = await pool.query(
    33→      `SELECT j.*, u.company_name as poster_company, u.name as poster_name
    34→       FROM jobs j
    35→       LEFT JOIN users u ON j.user_id = u.id
    36→       WHERE j.id = $1`,
    37→      [req.params.id]
    38→    );
    39→
    40→    if (result.rows.length === 0) {
    41→      return res.status(404).json({ error: 'Job not found' });
    42→    }
    43→
    44→    res.json({ job: result.rows[0] });
    45→  } catch (err) {
    46→    console.error('Get job error:', err);
    47→    res.status(500).json({ error: 'Failed to fetch job' });
    48→  }
    49→});
    50→
    51→// Create job (hiring managers and recruiters)
    52→router.post('/', authMiddleware, requireRole('hiring_manager', 'admin', 'recruiter', 'employer'), async (req, res) => {
    53→  try {
    54→    const { title, company, description, requirements, location, salary_range, job_type, screening_questions,
    55→            country_code, currency_code, salary_min, salary_max } = req.body;
    56→
    57→    if (!title) {
    58→      return res.status(400).json({ error: 'Job title is required' });
    59→    }
    60→
    61→    // Default country from company if not specified
    62→    let jobCountry = country_code || 'US';
    63→    let jobCurrency = currency_code || 'USD';
    64→    if (!country_code && req.user.company_id) {
    65→      try {
    66→        const companyCountry = await pool.query(
    67→          'SELECT primary_country FROM companies WHERE id = $1',
    68→          [req.user.company_id]
    69→        );
    70→        if (companyCountry.rows.length > 0 && companyCountry.rows[0].primary_country) {
    71→          jobCountry = companyCountry.rows[0].primary_country;
    72→          // Get currency from country config
    73→          const countryConfig = require('../services/country-config');
    74→          const cc = await countryConfig.getCountry(jobCountry);
    75→          if (cc) jobCurrency = cc.currency_code;
    76→        }
    77→      } catch (e) { /* use defaults */ }
    78→    }
